var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"작전 종료. 집으로 돌아갈 시간이야.","JPN":"作戦終了。家に帰る時間だよ。","ENG":"Mission complete. It's time to go home.","TWN":"作戰結束。是時候回家了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"참, 말했던 비품은 챙겼어?","JPN":"そういえば、備品は持ってきた？","ENG":"By the way, did you grab the supplies I mentioned?","TWN":"對了，你說的東西帶了嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"비품?","JPN":"備品？","ENG":"Supplies?","TWN":"東西？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"또 까먹은 거야? 이번 경연 출품에 꼭 필요한 비품이 있다고 했잖아.","JPN":"また忘れたの？　今回のコンテスト出品に欠かせない備品があるって言ったじゃん。","ENG":"You forgot again? I told you we needed those for the competition entry.","TWN":"你又忘了嗎？我說過這次比賽展出，必須要有那個東西。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"정말-","JPN":"もう～","ENG":"Ugh…","TWN":"真是的—"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내가 왜 어제 말한 것도 까먹고 기계도 만질 줄 모르는 사람이랑 일하게 된 건지 모르겠다니까.","JPN":"なんで昨日言ったことも1日で忘れる機械音痴と一緒に働くことになったのやら。","ENG":"I still don't get why I ended up working with someone who forgets everything I said just the day before and can't even handle machines.","TWN":"我真不明白，為什麼我會和一個連昨天說過的話都會忘記，也不會操作機器的人一起工作。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 너보다 강하기 때문이다.","JPN":"私がお前より強いからだ。","ENG":"Because I'm stronger than you.","TWN":"因為她比你更強。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"네 네- 내일 채굴 호위도 잘 부탁드립니다, 파트너 어르신-","JPN":"はい、はい～明日の採掘の護衛もどうぞよろしくお願いしますよ。パートナーのおばあさん～","ENG":"Yeah, yeah. Thanks in advance for guarding the mining site tomorrow, granny.","TWN":"是是—明天的採礦護衛也拜託你了，夥伴阿姨—"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"용병 일이 돈이 된다는 건 인정하지만, 왜 그렇게 채굴 의뢰에 집착하지?","JPN":"傭兵の仕事が儲かることは分かるが、なぜそこまで採掘の依頼にこだわる？","ENG":"I'll admit mercenary work pays well, but why are you so obsessed with mining jobs?","TWN":"傭兵的工作賺錢是沒錯，但你為什麼這麼執著於採礦委託？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그야 내 능력이 막힌 길을 뚫는데 유용하니까.","JPN":"そりゃもちろん、私の能力は塞がった道を開けるのに有用だから。","ENG":"Because my abilities are perfect for clearing blocked paths.","TWN":"因為我的能力很適合開闢堵塞的道路啊。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"업계에서도 이제 제법 유명해. 길 잘 뚫는 여자로.","JPN":"業界でも結構有名なんだよ。道開けが上手い女だって。","ENG":"I'm kind of famous for that now. You know, as the girl who opens the way.","TWN":"在業界已經小有名氣了。是個很會開路的女人。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"공고에는 뭐든 잘 녹이는 여자라고 되어있던데.","JPN":"募集には、何でも溶かす女だと書いてあったが。","ENG":"I saw a listing that called you the girl who melts anything.","TWN":"但公告上寫著是個很會溶解東西的女人。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"별명은 많은 편이 유명세를 타기 쉽거든.","JPN":"二つ名は多いほど有名になりやすいんだ。","ENG":"Catchy names make for better marketing.","TWN":"外號多一點比較容易出名嘛。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그렇게 내가 계속 의뢰를 받아야 어르신을 계속 부려 먹지. 우리 순진한 어르신을 냉혹한 사기꾼들이 넘치는 사회로 내보낼 순 없잖아.","JPN":"そうやって私がどんどん依頼を受けないと、おばあさんを雇えないでしょう。ピュアなおばあさんを冷酷な詐欺師が蔓延る社会へ送り出すわけにはいかないじゃん。","ENG":"Besides, I need steady gigs if I'm gonna keep bossing you around. No way I'm letting sweet ol' granny loose in a world full of scammers.","TWN":"只有我繼續接委託，才能繼續操縱你。不能把我們單純的阿姨丟到充斥冷酷騙子的社會裡去吧。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"혹시 채광 의뢰에 집착하는 이유가…","JPN":"もしかして採掘の依頼に執着するのは……","ENG":"Wait, are you taking mining jobs because…","TWN":"你這麼執著於採礦委託…"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아직도 <color=#ffd34c>검은 이터니움</color>을 찾고 있기 때문인가?","JPN":"まだ<color=#ffd34c>黒いエタニウム</color>を探しているからなのか？","ENG":"You're still looking for the <color=#ffd34c>Dark Eternium</color>?","TWN":"是不是還在找<color=#ffd34c>黑色永恆之金</color>？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"술김에 얘기했던 건데, 그건 잘도 기억하네.","JPN":"酔っぱらってポロっと話しただけなのに、よく覚えてるんだね。","ENG":"Wow, you actually remembered that? I only said it while tipsy.","TWN":"那是酒後說的，你倒是記得很清楚。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 얘길 할 때까지만 해도 난 네가 애정결핍에 시달리는 환자라고 생각했다.","JPN":"あの話を聞くまで、私はお前のことを愛情の欠如に悩む患者だと思っていた。","ENG":"Back then, I thought you were just some lonely nutcase.","TWN":"說那話的時候，我還以為你是個患有情感缺失症的患者。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"갑자기 아무 이유없이 허전함을 느낀 적 없냐느니, 검은 이터니움에 비친 어떤 남자를 봤다느니 같은 헛소리를 지껄여서 말이지.","JPN":"突然わけもなく虚しさを感じることはないかとか、黒いエタニウムの中にある男を見たとかいう戯言を言うものだから。","ENG":"Randomly asking if I felt empty, and spouting nonsense about seeing some guy in the Dark Eternium.","TWN":"你說什麼毫無理由感到空虛，又說在黑色永恆之金裡看到了某個男人，說些瘋言瘋語。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 말처럼…","JPN":"確かに……","ENG":"Like you said…","TWN":"也許就像你說的…"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내가 이상한 걸지도 모르겠네.","JPN":"私、おかしいのかもしれないね。","ENG":"Maybe I am crazy.","TWN":"是我不正常吧。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"침식지대를 자주 들락거리는 사람이 착란증세를 겪는 건, 제법 흔한 일이니까.","JPN":"侵食地帯に頻繁に出入りする人間が錯乱状態に陥るのはよくあることだし。","ENG":"It's not unusual. People who visit Corrupted Areas often enough tend to lose their grip.","TWN":"經常出入侵蝕區的人，產生幻覺是很常見的事。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"채광 의뢰가 부담되면 관둬도 돼. 어르신을 억지로 붙잡진 않을게.","JPN":"採掘依頼につき合うのが負担になるなら、やめていいんだよ。おばあさんに無理強いはしない。","ENG":"If the mining jobs are too much, you can drop out. I won't stop you.","TWN":"如果採礦委託讓你覺得有壓力，放棄也沒關係。我不會強留你。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"관두겠다는 말은 한 적 없어.","JPN":"……やめるとは言っていない。","ENG":"I never said I was quitting.","TWN":"我沒說要放棄。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나야 네 회사에서 월급만 받으면 그만이니까.","JPN":"私はお前の会社から給料がもらえばそれでいい。","ENG":"I just want my paycheck.","TWN":"我只要能從你公司領薪水就行。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"또 술집에서 번 돈 탕진하러 가는 거야?","JPN":"また給料使い果たしに酒場に行くの？","ENG":"Heading off to blow your salary at another bar again?","TWN":"你又要去把在酒館賺的錢花光嗎？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};